diff --git a/packages/ui/src/engine/pixel-characters.ts b/packages/ui/src/engine/pixel-characters.ts
index 1234567..89abcde 100644
--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -930,10 +930,110 @@ function drawCharacter(character: Character, ctx: CanvasRenderingContext2D, x: number, y: number) {
   // Calculate frame index based on time and frame duration
   const now = Date.now();
   const frameIndex = Math.floor(now / IDLE_FRAME_DURATION) % frames.length;
   const frame = frames[frameIndex];

   // For breathing vertical offset: offset y by -1 on frame 1 (breathing up)
   let yOffset = 0;
   if (frameIndex === 1) {
     yOffset = -1;
   }
-
-  drawSprite(frame, ctx, x, y + yOffset);
+  drawSprite(frame, ctx, x, y + yOffset);
+
+  // Draw status effect overlay after character sprite
+  drawStatusEffect(character, ctx, x, y + yOffset, now);
+}
+
+function drawStatusEffect(character: Character, ctx: CanvasRenderingContext2D, x: number, y: number, now: number) {
+  if (!character.status) return;
+
+  switch (character.status) {
+    case 'Idle':
+      drawIdleEffect(ctx, x, y, now);
+      break;
+    case 'Working':
+      drawWorkingEffect(ctx, x, y, now);
+      break;
+    case 'Reviewing':
+      drawReviewingEffect(ctx, x, y, now);
+      break;
+    case 'Stalled':
+      drawStalledEffect(ctx, x, y, now);
+      break;
+    case 'Failed':
+      drawFailedEffect(ctx, x, y, now);
+      break;
+  }
+}
+
+// Idle: subtle pulsing white glow (opacity oscillates 0.1-0.3)
+function drawIdleEffect(ctx: CanvasRenderingContext2D, x: number, y: number, now: number) {
+  const pulse = 0.2 + 0.1 * Math.sin(now / 500 * Math.PI * 2);
+  ctx.save();
+  ctx.shadowColor = `rgba(255,255,255,${pulse.toFixed(3)})`;
+  ctx.shadowBlur = 8;
+  ctx.globalAlpha = pulse;
+  ctx.strokeStyle = `rgba(255,255,255,${pulse.toFixed(3)})`;
+  ctx.lineWidth = 2;
+  // Draw a glow rectangle around the character sprite (16x22)
+  ctx.strokeRect(x - 1, y - 1, 16 + 2, 22 + 2);
+  ctx.restore();
+}
+
+// Working: golden sparkle particles around character
+function drawWorkingEffect(ctx: CanvasRenderingContext2D, x: number, y: number, now: number) {
+  const sparkleCount = 6;
+  ctx.save();
+  for (let i = 0; i < sparkleCount; i++) {
+    // Each sparkle moves in a small circular orbit with phase offset
+    const angle = ((now / 1000) * 2 * Math.PI + (i * (2 * Math.PI / sparkleCount))) % (2 * Math.PI);
+    const radius = 10;
+    const sx = x + 8 + Math.cos(angle) * radius;
+    const sy = y + 11 + Math.sin(angle) * radius;
+    const sparkleOpacity = 0.5 + 0.5 * Math.sin(now / 200 + i);
+    ctx.fillStyle = `rgba(255, 215, 0, ${sparkleOpacity.toFixed(3)})`; // gold color
+    ctx.beginPath();
+    ctx.arc(sx, sy, 1.5, 0, 2 * Math.PI);
+    ctx.fill();
+  }
+  ctx.restore();
+}
+
+// Reviewing: magnifying glass icon above head
+function drawReviewingEffect(ctx: CanvasRenderingContext2D, x: number, y: number, now: number) {
+  ctx.save();
+  const iconX = x + 8;
+  const iconY = y - 10;
+  ctx.lineWidth = 2;
+  ctx.strokeStyle = '#444';
+  ctx.fillStyle = '#ccc';
+  // Draw magnifying glass circle
+  ctx.beginPath();
+  ctx.arc(iconX, iconY, 6, 0, 2 * Math.PI);
+  ctx.fill();
+  ctx.stroke();
+  // Draw handle
+  ctx.beginPath();
+  ctx.moveTo(iconX + 4, iconY + 4);
+  ctx.lineTo(iconX + 8, iconY + 8);
+  ctx.stroke();
+  ctx.restore();
+}
+
+// Stalled: red pulsing outline
+function drawStalledEffect(ctx: CanvasRenderingContext2D, x: number, y: number, now: number) {
+  const pulse = 0.5 + 0.5 * Math.sin(now / 400 * Math.PI * 2);
+  ctx.save();
+  ctx.strokeStyle = `rgba(231, 76, 60, ${pulse.toFixed(3)})`; // red
+  ctx.lineWidth = 3;
+  ctx.shadowColor = `rgba(231, 76, 60, ${pulse.toFixed(3)})`;
+  ctx.shadowBlur = 10;
+  ctx.strokeRect(x - 2, y - 2, 16 + 4, 22 + 4);
+  ctx.restore();
+}
+
+// Failed: dark gray desaturation overlay
+function drawFailedEffect(ctx: CanvasRenderingContext2D, x: number, y: number, now: number) {
+  ctx.save();
+  ctx.fillStyle = 'rgba(50, 50, 50, 0.5)';
+  ctx.fillRect(x, y, 16, 22);
+  ctx.restore();
+}
+
